import java.util.Scanner;

public class SecureBufferCopy {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        char[] buffer = new char[10];
        int length = Math.min(input.length(), buffer.length); // Ensure length does not exceed buffer size

        // Copy the input string into the buffer with proper boundary checking
        for (int i = 0; i < length; i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Buffer overflow vulnerability fixed!");
    }
}

